def make_simplified_withdraw(balance):
    def withdraw(amount):
        nonlocal balance
        balance = balance - amount
        return balance
    return withdraw

def stream_withdraw(balance, amount_stream):
    return pair(balance,
                lambda: stream_withdraw(balance - head(amount_stream),
                                        stream_tail(amount_stream)))
